<script setup lang="ts">import{ref}from'vue';import{useSkillsStore}from'../store';const store=useSkillsStore(),title=ref(''),team=ref('Policy & Risk'),seats=ref(12),message=ref('');const submit=()=>{if(title.value.trim().length<4||seats.value<1){message.value='Add a cohort name and at least one seat.';return}store.createCohort(title.value,team.value,seats.value);title.value='';message.value='Cohort plan created.'}</script>
<template><main class="page"><span class="eyebrow">Enterprise mobility</span><h1>Workforce planner</h1><p>Turn capability gaps into accountable team learning plans.</p><div class="studio"><form @submit.prevent="submit"><h2>Create a cohort</h2><label>Cohort name<input v-model="title"/></label><label>Business team<select v-model="team"><option>Policy & Risk</option><option>Technology</option><option>Operations</option><option>Sustainability</option></select></label><label>Seats<input v-model.number="seats" type="number" min="1" max="100"/></label><button>Create cohort</button><p role="status">{{message}}</p></form><section><h2>Active plans</h2><div v-for="item in store.cohorts" :key="item.title" class="slate"><div><b>{{item.title}}</b><small>{{item.team}} · {{item.seats}} seats</small></div><span>{{item.status}}</span></div></section></div></main></template>
